<?php $detail=is_array($detail??null)?$detail:[]; $module=is_array($detail['module']??null)?$detail['module']:[]; $roles=is_array($detail['roles']??null)?$detail['roles']:[]; $permissions=is_array($detail['permissions']??null)?$detail['permissions']:[]; $summary=is_array($detail['summary']??null)?$detail['summary']:[]; ?>
<section class="card"><h1>Auditoría módulo: <?= htmlspecialchars((string)($module['name']??$module['code']??''),ENT_QUOTES,'UTF-8') ?></h1><p>Código: <?= htmlspecialchars((string)($module['code']??''),ENT_QUOTES,'UTF-8') ?> · Roles del tenant: <?= count($roles) ?></p></section>
<section class="card"><h2>Resumen</h2><p>Total permisos: <?= (int)($summary['total_permissions']??0) ?> · Faltantes (sin rol): <?= (int)($summary['missing_permissions']??0) ?></p></section>
<section class="card"><h2>Permisos por rol</h2><table><thead><tr><th>Permiso</th><th>Nombre</th><th>Roles asignados</th></tr></thead><tbody><?php foreach($permissions as $p): $assigned=is_array($p['roles']??null)?$p['roles']:[]; ?><tr><td><?= htmlspecialchars((string)($p['code']??''),ENT_QUOTES,'UTF-8') ?></td><td><?= htmlspecialchars((string)($p['name']??''),ENT_QUOTES,'UTF-8') ?></td><td><?php if($assigned===[]): ?>Sin asignación<?php else: ?><ul><?php foreach($assigned as $r): ?><li><?= htmlspecialchars((string)($r['name']??$r['slug']??''),ENT_QUOTES,'UTF-8') ?></li><?php endforeach; ?></ul><?php endif; ?></td></tr><?php endforeach; ?></tbody></table><p><a href="/security/permissions-audit">Volver</a></p></section>
